// Load business config — in production, this reads from a file or database.
// For now, it's embedded. Replace this with a Read File node or HTTP Request
// pointed at your business-config JSON.

const config = {
  "business": {
    "name": "Aroostook Family Dental",
    "tagline": "Your hometown dental office since 1998",
    "address": {
      "street": "45 Main Street",
      "city": "Presque Isle",
      "state": "ME",
      "zip": "04769"
    },
    "phone": "(207) 555-0142",
    "email": "info@aroostookfamilydental.com",
    "website": "https://aroostookfamilydental.com"
  },
  "hours": {
    "monday": { "open": "08:00", "close": "17:00" },
    "tuesday": { "open": "08:00", "close": "17:00" },
    "wednesday": { "open": "08:00", "close": "17:00" },
    "thursday": { "open": "08:00", "close": "15:00" },
    "friday": { "open": "08:00", "close": "12:00" },
    "saturday": "closed",
    "sunday": "closed"
  },
  "services": [
    { "name": "Cleaning & Exam", "duration_minutes": 60, "price_range": "$150-$250" },
    { "name": "Filling", "duration_minutes": 45, "price_range": "$175-$350" },
    { "name": "Crown", "duration_minutes": 90, "price_range": "$800-$1500" },
    { "name": "Emergency Visit", "duration_minutes": 30, "price_range": "Varies" },
    { "name": "Whitening", "duration_minutes": 60, "price_range": "$300-$500" }
  ],
  "faq": [
    { "question": "Do you accept my insurance?", "answer": "We accept most major dental insurance plans including Delta Dental, Cigna, Aetna, and MetLife. Call us to verify your specific plan." },
    { "question": "Are you accepting new patients?", "answer": "Yes, we're always welcoming new patients." },
    { "question": "What should I do in a dental emergency?", "answer": "Call us immediately at (207) 555-0142. If it's after hours, leave a message." },
    { "question": "Do you offer payment plans?", "answer": "Yes, we offer CareCredit financing and in-house payment plans for procedures over $500." },
    { "question": "How often should I come in for a cleaning?", "answer": "We recommend every 6 months for most patients." }
  ],
  "policies": {
    "cancellation": "Please give us at least 24 hours notice if you need to cancel or reschedule.",
    "late_arrival": "If you arrive more than 15 minutes late, we may need to reschedule.",
    "new_patient_forms": "New patients should arrive 15 minutes early to complete paperwork."
  },
  "ai_receptionist": {
    "name": "Amy",
    "personality": "Friendly, professional, and helpful.",
    "greeting": "Hi! This is Amy at Aroostook Family Dental. How can I help you today?",
    "escalation_triggers": ["billing disputes", "complaints about care", "requests to speak with the dentist directly", "legal or insurance claim questions"],
    "off_hours_message": "We're currently closed, but I can take a message and someone will get back to you when we open."
  },
  "owner": {
    "name": "Dr. Sarah Mitchell",
    "telegram_chat_id": "",
    "email": "sarah@aroostookfamilydental.com"
  }
};

return [{ json: config }];

// Determine current business hours status
const config = $('Load Business Config').item.json;
const now = new Date();
const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const today = dayNames[now.getDay()];
const hours = config.hours[today];

let isOpen = false;
let statusMessage = '';

if (hours === 'closed') {
  statusMessage = `We're closed today (${today}).`;
} else {
  const currentTime = now.getHours() * 100 + now.getMinutes();
  const openTime = parseInt(hours.open.replace(':', ''));
  const closeTime = parseInt(hours.close.replace(':', ''));

  if (currentTime >= openTime && currentTime < closeTime) {
    isOpen = true;
    statusMessage = `We're open today until ${hours.close}.`;
  } else if (currentTime < openTime) {
    statusMessage = `We're not open yet today. We open at ${hours.open}.`;
  } else {
    statusMessage = `We're closed for today. We were open until ${hours.close}.`;
  }
}

// Pass through the original webhook data plus hours status
const webhookData = $('Chat Webhook').item.json;
return [{
  json: {
    ...webhookData,
    business_status: {
      is_open: isOpen,
      message: statusMessage,
      today: today,
      hours: hours
    }
  }
}];

